it("should apply cursed surcharge only to the cursed item — cursed sword + plain amulet: 100 + 50 (curse) + 60 = 210 G before policy modifiers, + 5 G fee = 215 G", () => {
  const result = claimOffice({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [
          { type: "sword", material: "steel", enchantment: 0, cursed: true },
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      },
    ],
  });
  expect(result).toEqual({ results: [{ premium: 215 }] });
});
